import React, { useState, useEffect } from 'react';
import Navbar from './components/Navbar';
import Hero from './components/Hero';
import About from './components/About';
import Skills from './components/Skills';
import Services from './components/Services';
import Portfolio from './components/Portfolio';
import Contact from './components/Contact';
import Footer from './components/Footer';

const App: React.FC = () => {
  const [scrolled, setScrolled] = useState(false);

  useEffect(() => {
    const handleScroll = () => {
      setScrolled(window.scrollY > 50);
    };

    // Intersection Observer for Scroll Reveals
    const observerOptions = {
      threshold: 0.15,
      rootMargin: "0px 0px -50px 0px"
    };

    const observer = new IntersectionObserver((entries) => {
      entries.forEach((entry) => {
        if (entry.isIntersecting) {
          entry.target.classList.add('active');
        }
      });
    }, observerOptions);

    const revealElements = document.querySelectorAll('.reveal, .reveal-left, .reveal-right');
    revealElements.forEach((el) => observer.observe(el));

    window.addEventListener('scroll', handleScroll);
    return () => {
      window.removeEventListener('scroll', handleScroll);
      revealElements.forEach((el) => observer.unobserve(el));
    };
  }, []);

  return (
    <div className="min-h-screen bg-purple-gradient relative selection:bg-purple-500 selection:text-white">
      {/* Decorative background blobs */}
      <div className="fixed top-0 left-0 w-full h-full overflow-hidden -z-10 pointer-events-none">
        <div className="absolute top-[10%] left-[5%] w-96 h-96 bg-purple-600/20 rounded-full blur-[120px] animate-pulse"></div>
        <div className="absolute bottom-[20%] right-[10%] w-[500px] h-[500px] bg-indigo-600/10 rounded-full blur-[150px]"></div>
      </div>

      <Navbar scrolled={scrolled} />

      <main>
        <Hero />
        <About />
        <Skills />
        <Services />
        <Portfolio />
        <Contact />
      </main>

      <Footer />
    </div>
  );
};

export default App;

import React, { useEffect, useRef, useState } from 'react';
import { SKILLS } from '../constants';

const Skills: React.FC = () => {
  const [isVisible, setIsVisible] = useState(false);
  const sectionRef = useRef<HTMLElement>(null);

  useEffect(() => {
    const observer = new IntersectionObserver(
      ([entry]) => {
        if (entry.isIntersecting) {
          setIsVisible(true);
          observer.disconnect();
        }
      },
      { threshold: 0.2 }
    );

    if (sectionRef.current) {
      observer.observe(sectionRef.current);
    }

    return () => observer.disconnect();
  }, []);

  return (
    <section ref={sectionRef} id="skills" className="py-24 px-6 bg-slate-900/40">
      <div className="max-w-7xl mx-auto">
        <div className="text-center mb-16 space-y-4 reveal">
          <h2 className="text-purple-400 font-bold uppercase tracking-widest text-sm">Technical Proficiency</h2>
          <h3 className="text-4xl md:text-5xl font-bold font-display">My Cutting Edge <span className="text-gradient">Skills</span></h3>
          <p className="text-slate-400 max-w-2xl mx-auto">Equipped with the industry-standard tools and techniques to deliver high-quality video production.</p>
        </div>

        <div className="grid md:grid-cols-2 gap-x-16 gap-y-10">
          {SKILLS.map((skill, index) => (
            <div key={index} className={`space-y-4 reveal stagger-${index + 1}`}>
              <div className="flex justify-between items-end">
                <span className="text-xl font-bold text-white tracking-tight">{skill.name}</span>
                <span className="text-purple-400 font-bold">{skill.level}%</span>
              </div>
              <div className="h-2 w-full bg-white/5 rounded-full overflow-hidden">
                <div 
                  className="h-full bg-gradient-to-r from-purple-600 to-indigo-500 rounded-full transition-all duration-[1.5s] ease-out"
                  style={{ width: isVisible ? `${skill.level}%` : '0%' }}
                ></div>
              </div>
            </div>
          ))}
        </div>

        <div className="mt-20 flex flex-wrap justify-center gap-12 grayscale opacity-40 reveal">
          <span className="text-3xl font-black italic">PR</span>
          <span className="text-3xl font-black italic">AE</span>
          <span className="text-3xl font-black italic">DR</span>
          <span className="text-3xl font-black italic">PS</span>
          <span className="text-3xl font-black italic">AI</span>
        </div>
      </div>
    </section>
  );
};

